const httpRequest = async (opts) => { const r = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers, body: opts.body }); const t = await r.text(); try { return JSON.parse(t); } catch(e) { return t; } };
const child = $input.item.json;
const headers = { 'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk', 'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk' };
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const yesterdayStart = new Date(todayStart.getTime() - 86400000);
let lastSession = null, history = [], dynamicContext = {}, pushSubscription = null;

try {
  const sessions = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/story_sessions?child_id=eq.${child.id}&created_at=gte.${yesterdayStart.toISOString()}&created_at=lt.${todayStart.toISOString()}&order=created_at.desc&limit=1&select=*`, headers });
  lastSession = Array.isArray(sessions) && sessions.length > 0 ? sessions[0] : null;
} catch(e) { console.log('Session fetch error:', e.message); }

if (!lastSession) {
  return [{ json: { session_found: false, child } }];
}

try {
  const h = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/story_sessions?child_id=eq.${child.id}&created_at=lt.${yesterdayStart.toISOString()}&order=created_at.desc&limit=6&select=id,night_type,story_prompt,source_story_title,themes,parent_note,created_at`, headers });
  history = Array.isArray(h) ? h.reverse() : [];
} catch(e) { console.log('History fetch error:', e.message); }

try {
  const ctx = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/child_dynamic_context?child_id=eq.${child.id}&limit=1&select=*`, headers });
  dynamicContext = Array.isArray(ctx) && ctx.length > 0 ? ctx[0] : {};
} catch(e) { console.log('Dynamic context fetch error:', e.message); }

try {
  const prefs = await httpRequest({ method: 'GET', url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/notification_preferences?user_id=eq.${child.user_id}&child_id=eq.${child.id}&limit=1&select=push_subscription`, headers });
  pushSubscription = Array.isArray(prefs) && prefs.length > 0 ? prefs[0].push_subscription : null;
} catch(e) { console.log('Prefs fetch error:', e.message); }

return [{ json: { session_found: true, lastSession, history, dynamicContext, pushSubscription, child } }];

const { lastSession: session, history, dynamicContext: ctx, pushSubscription, child } = $input.item.json;
const isPlayback = session.night_type === 'playback';

const historyText = history.length > 0
  ? history.map(s => {
      const d = new Date(s.created_at).toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
      return s.night_type === 'playback'
        ? `${d}: PLAYBACK — "${s.source_story_title || 'Unknown'}"`
        : `${d}: CO-CREATION — prompt: "${s.story_prompt || 'none'}", themes: ${(s.themes || []).join(', ') || 'none'}`;
    }).join('
')
  : 'No prior history — this is among the first nights of use.';

const nightContext = isPlayback
  ? `NIGHT TYPE: Comfort playback
Replayed story: "${session.source_story_title || 'Unknown'}"
Times played in last 14 days: ${session.playback_count_14d ?? 'Unknown'}
Parent note: ${session.parent_note || 'None'}`
  : `NIGHT TYPE: Co-creation
Story prompt (child's words): ${session.story_prompt || 'None'}
Parent note: ${session.parent_note || 'None'}
Themes generated: ${(session.themes || []).join(', ') || 'Not tagged'}
Villain appeared: ${session.villain_appeared ?? 'Unknown'}`;

const allies = (ctx.characters || []).filter(c => c.name).map(c => `${c.name} (${c.role || 'ally'})`).join(', ') || 'None noted';
const hasEnoughHistory = history.length >= 4;

const systemPrompt = `You are a warm, perceptive child development observer helping parents notice what is happening in their child's emotional world through bedtime stories.

Generate exactly three observations for the parent to react to. Each must be a different type:
- THEME: A theme or topic from last night, especially if it connects to the child's known fears or stressors
- PATTERN: Something appearing across multiple nights in the recent history. Only use this type if 4+ nights of history exist — if not, generate a second THEME observation instead
- LANGUAGE: A specific word, phrase, image, or character choice the child made that is worth a parent noticing

QUALITY STANDARD: Before including any observation ask — would this parent have noticed and named this themselves without the app? If yes, replace it with something more specific. Generic observations must not be surfaced.

TONE: Warm, plain language. Observational not diagnostic. Curious not alarming. Never clinical. Never suggest a condition or problem. The parent is the expert on their child — you are pointing at something worth noticing. Maximum 2 sentences per observation.

${isPlayback ? 'PLAYBACK NIGHT RULE: Do not observe story content. Reflect on the return itself — what returning to this specific story might signal. A repeated return in a neurodivergent child often signals a need for predictability, regulation, or emotional safety.' : ''}

Return valid JSON only — no preamble, no markdown fences:
{
  "observations": [
    { "type": "THEME", "text": "one specific sentence, parent-readable" },
    { "type": "${hasEnoughHistory ? 'PATTERN' : 'THEME'}", "text": "one specific sentence, parent-readable" },
    { "type": "LANGUAGE", "text": "one specific sentence, parent-readable" }
  ]
}`;

const userPrompt = `CHILD PROFILE:
Name: ${child.name}, Age: ${child.age}${child.gender_pronoun ? `, Pronouns: ${child.gender_pronoun}` : ''}
Personality: ${child.personality_description || 'Not provided'}
Neuro profile: ${child.neuro_profile || 'Not specified'}
Neuro flags: ${(child.neuro_flags || []).join(', ') || 'None'}
Interests: ${(child.interests || []).join(', ') || 'Not specified'}
Family context: ${child.family_structure || 'Not provided'}

CONTEXT:
Fear flags: ${(ctx.fear_flags || []).join(', ') || 'None noted'}
Standing fears: ${ctx.standing_fears || 'None noted'}
Current stressors: ${ctx.current_stressors || 'None noted'}
Allies and characters: ${allies}

LAST NIGHT:
${nightContext}

RECENT HISTORY (oldest first, ${history.length} nights):
${historyText}

Generate three observations now.`;

return [{ json: {
  systemPrompt,
  userPrompt,
  child_id: child.id,
  user_id: child.user_id,
  session_id: session.id,
  night_type: session.night_type,
  pushSubscription,
  childName: child.name,
  storyPrompt: session.story_prompt,
  sourceStoryTitle: session.source_story_title
} }];

const httpRequest = async (opts) => { const r = await fetch(opts.url, { method: opts.method || 'GET', headers: opts.headers, body: opts.body }); const t = await r.text(); try { return JSON.parse(t); } catch(e) { return t; } };
const claudeResponse = $input.item.json;
const prev = $('Build Claude Prompt').item.json;

let observations = [];
try {
  const text = claudeResponse.content?.[0]?.text || '';
  const cleaned = text.replace(/```json\s*/g, '').replace(/```\s*$/g, '').trim();
  const parsed = JSON.parse(cleaned);
  observations = parsed.observations || [];
} catch(e) {
  throw new Error('Failed to parse Claude observations: ' + e.message);
}

if (observations.length !== 3) {
  throw new Error(`Expected 3 observations, got ${observations.length}`);
}

const headers = {
  'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk',
  'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImptZHloeGViY29zeWp5YWZ6c3NzIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDAyOTMyNSwiZXhwIjoyMDg1NjA1MzI1fQ.jXeyWib0H0D5JEbSS5m_h9XI82MWI_shpj0r1DfxnGk',
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

await httpRequest({
  method: 'POST',
  url: `https://jmdyhxebcosyjyafzsss.supabase.co/rest/v1/morning_reactions`,
  headers,
  body: JSON.stringify({
    child_id: prev.child_id,
    user_id: prev.user_id,
    session_id: prev.session_id,
    night_type: prev.night_type,
    observations: observations,
    reactions: [],
    skipped: false,
    generated_at: new Date().toISOString()
  })
});

let notifBody;
if (prev.night_type === 'playback') {
  notifBody = `${prev.childName} chose a comfort story last night — we noticed something worth seeing.`;
} else if (prev.storyPrompt) {
  const summary = prev.storyPrompt.length > 45 ? prev.storyPrompt.substring(0, 45) + '...' : prev.storyPrompt;
  notifBody = `${prev.childName} wanted "${summary}" — we noticed something. Tap to see.`;
} else {
  notifBody = `Three things worth noticing from ${prev.childName}'s night. Tap to see.`;
}

if (prev.pushSubscription) {
  await httpRequest({
    method: 'POST',
    url: $vars.PUSH_LAMBDA_URL,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      subscription: prev.pushSubscription,
      payload: {
        title: 'DreamStation ✨',
        body: notifBody,
        tag: 'morning-reflection',
        data: { type: 'morning_reflection', session_id: prev.session_id }
      }
    })
  }).catch(e => console.log('Push failed (non-fatal):', e.message));
}

return [{ json: { done: true, child_id: prev.child_id } }];
